public class Backtrack extends Module {
    private final ArrayList<Packet> packets = new ArrayList<>();
    private EntityLivingBase entity = null;
    public static EntityPlayer target = null;
    private INetHandler packetListener = null;
    private WorldClient lastWorld;
    private final TimeUtil timeUtil = new TimeUtil();

    public Backtrack() {
        super("Backtrack", Module.Type.Combat, "Backtrack", 0, Category.Combat);
        Aqua.setmgr.register(new Setting("Range", this, 6.0, 3.0, 6.0, false));
        Aqua.setmgr.register(new Setting("BacktrackMS", this, 1000.0, 50.0, 2000.0, false));
    }

    @Override
    public void onEvent(Event event) {
        if (event instanceof EventPacket) {
            EventPacket eventPacket = (EventPacket) event;
            if (eventPacket.getDirection() != EnumPacketDirection.CLIENTBOUND) return;

            this.packetListener = eventPacket.getNetHandler();
            Packet p = EventPacket.getPacket();

            // Track S14 for real position tracking
            if (p instanceof S14PacketEntity) {
                S14PacketEntity packet = (S14PacketEntity) EventPacket.getPacket();
                Entity entity1 = mc.theWorld.getEntityByID(packet.getEntityId());
                if (entity1 instanceof EntityLivingBase) {
                    EntityLivingBase entityLivingBase = (EntityLivingBase) entity1;
                    entityLivingBase.realPosX += packet.func_149062_c();
                    entityLivingBase.realPosY += packet.func_149061_d();
                    entityLivingBase.realPosZ += packet.func_149064_e();
                }
            }

            // Track S18 for teleport position reset
            if (p instanceof S18PacketEntityTeleport) { /* ... position reset ... */ }

            this.entity = target;
            if (this.entity == null) { this.resetPackets(eventPacket.getNetHandler()); return; }
            if (mc.theWorld != null && mc.thePlayer != null) {
                if (this.lastWorld != mc.theWorld) { this.resetPackets(eventPacket.getNetHandler()); this.lastWorld = mc.theWorld; return; }
                this.addPackets(p, eventPacket);
            }
            this.lastWorld = mc.theWorld;
        }
    }

    private boolean blockPacket(Packet packet) {
        // S32 is buffered for backtrack along with entity packets
        if (packet instanceof S33PacketTimeUpdate) return true;
        if (packet instanceof S00PacketKeepAlive) return true;
        if (packet instanceof C00PacketKeepAlive) return true;
        if (packet instanceof C0CPacketInput) return true;
        if (packet instanceof S12PacketEntityVelocity) return true;
        if (packet instanceof C01PacketEncryptionResponse) return true;
        if (packet instanceof S27PacketExplosion) return true;
        // <-- S32PacketConfirmTransaction is stored in backtrack buffer
        if (packet instanceof S32PacketConfirmTransaction) return true;
        if (packet instanceof S14PacketEntity) return true;
        if (packet instanceof S19PacketEntityHeadLook) return true;
        if (packet instanceof S18PacketEntityTeleport) return true;
        if (packet instanceof S0FPacketSpawnMob) return true;
        if (packet instanceof S08PacketPlayerPosLook) return true;
        return false;
    }

    private void resetPackets(INetHandler netHandler) {
        // Flush ALL queued packets to the handler
        if (this.packets.size() > 0) {
            for (; this.packets.size() != 0; this.packets.remove(this.packets.get(0))) {
                try { this.packets.get(0).processPacket(netHandler); }
                catch (ThreadQuickExitException var3) {}
            }
        }
    }

    private void addPackets(Packet packet, EventPacket eventPacket) {
        synchronized (this.packets) {
            if (this.blockPacket(packet)) {
                this.packets.add(packet);
                eventPacket.setCancelled(true);  // Cancel so vanilla handler doesn't process
            }
        }
    }
}

