package net.minecraft.network.play.server;

public class S32PacketConfirmTransaction implements Packet<INetHandlerPlayClient> {
    private int windowId;
    private short actionNumber;
    private boolean accepted;

    public S32PacketConfirmTransaction() {}
    public S32PacketConfirmTransaction(int windowIdIn, short actionNumberIn, boolean acceptedIn) {
        this.windowId = windowIdIn;
        this.actionNumber = actionNumberIn;
        this.accepted = acceptedIn;
    }
    public void processPacket(INetHandlerPlayClient handler) { handler.handleConfirmTransaction(this); }
    public int getWindowId() { return this.windowId; }
    public short getActionNumber() { return this.actionNumber; }
    public boolean isAccepted() { return this.accepted; }
}

// Disabler - S32Cancel mode:
if (event.getPacket() instanceof S32PacketConfirmTransaction) {
    event.setCancelled(true);
